import { getFromProps } from '../../helpers/getFromProps.js';
import { Markdown } from '../markdown/Markdown.js';
import { Text } from '../typography/Typography.js';
import styled, { css } from 'styled-components';

const fromProps = getFromProps();
const Title = styled(Text) ``;
const Description = styled(Markdown) `
  text-align: ${props => props.$textAlign};
  color: ${props => props.$cssConfig.description};
`;
const PlaceholderImage = styled.span `
  height: ${fromProps('imageSize')}px;
  width: ${fromProps('imageSize')}px;
`;
const placeholderCss = css `
  padding: ${fromProps('padding')}px;
  background: ${fromProps('background')};
  width: 100%;
  height: 100%;
  ${Title} {
    color: ${fromProps('title')};
  }
`;

export { Description, PlaceholderImage, Title, placeholderCss };
